            version = 2
            algorithm = strings.TrimSpace(line[len("PuTTY-User-Key-File-2:"):])
        } else if strings.HasPrefix(line, "PuTTY-User-Key-File-3:") {
            version = 3
            algorithm = strings.TrimSpace(line[len("PuTTY-User-Key-File-3:"):])
