            // Read public lines
            var b64 strings.Builder
            for j := 0; j < publicLines && i < len(lines); j++ {
                b64.WriteString(strings.TrimSpace(lines[i]))
                i++
            }
            var err error
            publicData, err = base64.StdEncoding.DecodeString(b64.String())
            if err != nil {
