            }
        } else if strings.HasPrefix(line, "Private-Lines:") {
            fmt.Sscanf(line, "Private-Lines: %d", &privateLines)
            var b64 strings.Builder
            for j := 0; j < privateLines && i < len(lines); j++ {
                b64.WriteString(strings.TrimSpace(lines[i]))
                i++
