// parsePuttyKey parses a PuTTY .ppk format private key (v2, unencrypted).
func parsePuttyKey(keyStr, passphrase string) (ssh.Signer, error) {
	lines := strings.Split(keyStr, "\n")

	type ppk struct {
		version      int
		algorithm    string
		encryption   string
		publicData   []byte
		privateData  []byte
	}
	var p ppk

	i := 0
	for i < len(lines) {
		line := strings.TrimSpace(lines[i])
		i++

		if line == "" || strings.HasPrefix(line, "Comment:") || strings.HasPrefix(line, "Private-MAC:") {
			continue
		}

		switch {
		case strings.HasPrefix(line, "PuTTY-User-Key-File-2:"):
			p.version = 2
			p.algorithm = strings.TrimSpace(line[len("PuTTY-User-Key-File-2:"):])
		case strings.HasPrefix(line, "PuTTY-User-Key-File-3:"):
			p.version = 3
			p.algorithm = strings.TrimSpace(line[len("PuTTY-User-Key-File-3:"):])
		case strings.HasPrefix(line, "Encryption:"):
			p.encryption = strings.TrimSpace(line[len("Encryption:"):])
		case strings.HasPrefix(line, "Public-Lines:"):
			n := 0
			fmt.Sscanf(line, "Public-Lines: %d", &n)
			var b strings.Builder
			for j := 0; j < n && i < len(lines); j, i = j+1, i+1 {
				b.WriteString(strings.TrimSpace(lines[i]))
			}
			var err error
			p.publicData, err = base64.StdEncoding.DecodeString(b.String())
			if err != nil {
				return nil, fmt.Errorf("PuTTY公钥解码失败: %w", err)
			}
		case strings.HasPrefix(line, "Private-Lines:"):
			n := 0
			fmt.Sscanf(line, "Private-Lines: %d", &n)
			var b strings.Builder
			for j := 0; j < n && i < len(lines); j, i = j+1, i+1 {
				b.WriteString(strings.TrimSpace(lines[i]))
			}
			var err error
			p.privateData, err = base64.StdEncoding.DecodeString(b.String())
			if err != nil {
				return nil, fmt.Errorf("PuTTY私钥解码失败: %w", err)
			}
		}
	}

	if p.version == 0 {
		return nil, fmt.Errorf("无法识别的PuTTY密钥格式")
	}
	if p.version == 3 {
		return nil, fmt.Errorf("暂不支持PuTTY v3格式（Argon2），请用PuTTYgen转换为v2格式")
	}
	if p.encryption != "none" {
		return nil, fmt.Errorf("暂不支持加密的PuTTY密钥，请用PuTTYgen去除密码保护")
	}
	if p.publicData == nil || p.privateData == nil {
		return nil, fmt.Errorf("PuTTY密钥数据不完整")
	}

	switch {
	case strings.Contains(p.algorithm, "ed25519") || strings.Contains(p.algorithm, "ssh-ed25519"):
		return makeEd25519SignerFromPPK(p.publicData, p.privateData)
	case strings.Contains(p.algorithm, "rsa") || strings.Contains(p.algorithm, "ssh-rsa"):
		return makeRSASignerFromPPK(p.publicData, p.privateData)
	default:
		return nil, fmt.Errorf("不支持的PuTTY密钥算法: %s", p.algorithm)
	}
}

// sshString reads a 4-byte length-prefixed string from data.
func sshString(data []byte) ([]byte, []byte, error) {
	if len(data) < 4 {
		return nil, nil, fmt.Errorf("ssh string: need 4 bytes for length, got %d", len(data))
	}
	l := binary.BigEndian.Uint32(data[:4])
	if uint32(len(data)) < 4+l {
		return nil, nil, fmt.Errorf("ssh string: need %d bytes, got %d", 4+l, len(data))
	}
	return data[4 : 4+l], data[4+l:], nil
}

// sshMPInt reads an SSH mpint from data.
func sshMPInt(data []byte) (*big.Int, []byte, error) {
	raw, rest, err := sshString(data)
	if err != nil {
		return nil, nil, err
	}
	return new(big.Int).SetBytes(raw), rest, nil
}

func makeEd25519SignerFromPPK(publicData, privateData []byte) (ssh.Signer, error) {
	// Public data: string("ssh-ed25519") + string(32-byte pubkey)
	algo, rest, err := sshString(publicData)
	if err != nil {
		return nil, fmt.Errorf("Ed25519公钥解析失败: %w", err)
	}
	_ = algo
	pubKeyBytes, _, err := sshString(rest)
	if err != nil {
		return nil, fmt.Errorf("Ed25519公钥解析失败: %w", err)
	}

	// Private data: mpint(32-byte seed)
	seedInt, _, err := sshMPInt(privateData)
	if err != nil {
		return nil, fmt.Errorf("Ed25519私钥解析失败: %w", err)
	}
	seedBytes := seedInt.Bytes()
	// Pad to 32 bytes
	if len(seedBytes) < ed25519.SeedSize {
		padded := make([]byte, ed25519.SeedSize)
		copy(padded[ed25519.SeedSize-len(seedBytes):], seedBytes)
		seedBytes = padded
	}

	privKey := ed25519.NewKeyFromSeed(seedBytes)
	// Sanity check: the derived public key should match
	if !ed25519.Equal(privKey.Public().(ed25519.PublicKey), ed25519.PublicKey(pubKeyBytes)) {
		return nil, fmt.Errorf("Ed25519密钥验证失败：公钥不匹配，文件可能已损坏")
	}

	return ssh.NewSignerFromKey(privKey)
}

func makeRSASignerFromPPK(publicData, privateData []byte) (ssh.Signer, error) {
	// Public data: string("ssh-rsa") + mpint(e) + mpint(n)
	_, rest, err := sshString(publicData)
	if err != nil {
		return nil, fmt.Errorf("RSA公钥解析失败: %w", err)
	}
	eInt, rest, err := sshMPInt(rest)
	if err != nil {
		return nil, fmt.Errorf("RSA公钥e解析失败: %w", err)
	}
	nInt, _, err := sshMPInt(rest)
	if err != nil {
		return nil, fmt.Errorf("RSA公钥n解析失败: %w", err)
	}

	// Private data: mpint(d) + mpint(p) + mpint(q) + mpint(iqmp)
	dInt, rest, err := sshMPInt(privateData)
	if err != nil {
		return nil, fmt.Errorf("RSA私钥d解析失败: %w", err)
	}
	pInt, rest, err := sshMPInt(rest)
	if err != nil {
		return nil, fmt.Errorf("RSA私钥p解析失败: %w", err)
	}
	qInt, rest, err := sshMPInt(rest)
	if err != nil {
		return nil, fmt.Errorf("RSA私钥q解析失败: %w", err)
	}
	iqmpInt, _, err := sshMPInt(rest)
	if err != nil {
		return nil, fmt.Errorf("RSA私钥iqmp解析失败: %w", err)
	}

	e := int(eInt.Int64())
	privKey := &rsa.PrivateKey{
		PublicKey: rsa.PublicKey{N: nInt, E: e},
		D:         dInt,
		Primes:    []*big.Int{pInt, qInt},
	}
	privKey.Precompute()

	return ssh.NewSignerFromKey(privKey)
}

